     1→const express = require('express');
     2→const Stripe = require('stripe');
     3→const { verifyToken } = require('../middleware/firebaseAuth');
     4→
     5→const router = express.Router();
     6→
     7→const stripe = new Stripe(process.env.STRIPE_SECRET_KEY || 'sk_test_placeholder', {
     8→  apiVersion: '2024-11-20.acacia',
     9→});
    10→
    11→// POST /api/stripe/create-checkout — Create Stripe Checkout Session
    12→router.post('/create-checkout', verifyToken, async (req, res) => {
    13→  const { priceId, mode: checkoutMode } = req.body;
    14→  const user = req.user;
    15→  const mode = checkoutMode === 'payment' ? 'payment' : 'subscription';
    16→
    17→  if (!priceId) {
    18→    return res.status(400).json({ error: 'Missing priceId' });
    19→  }
    20→
    21→  if (!process.env.STRIPE_SECRET_KEY || process.env.STRIPE_SECRET_KEY.includes('placeholder')) {
    22→    return res.status(503).json({ error: 'Payment system not configured yet. Please add Stripe keys.' });
    23→  }
    24→
    25→  try {
    26→    const sessionParams = {
    27→      payment_method_types: ['card'],
    28→      mode,
    29→      line_items: [{ price: priceId, quantity: 1 }],
    30→      success_url: `${process.env.FRONTEND_URL}/dashboard?payment=success`,
    31→      cancel_url: `${process.env.FRONTEND_URL}/pricing?payment=cancelled`,
    32→      client_reference_id: user.uid,
    33→      metadata: { firebaseUid: user.uid },
    34→      allow_promotion_codes: true,
    35→    };
    36→    if (mode === 'subscription') {
    37→      sessionParams.subscription_data = { metadata: { firebaseUid: user.uid } };
    38→    }
    39→    const session = await stripe.checkout.sessions.create(sessionParams);
    40→
    41→    res.json({ url: session.url, sessionId: session.id });
    42→  } catch (err) {
    43→    console.error('[Stripe Checkout Error]', err.message);
    44→    res.status(500).json({ error: err.message });
    45→  }
    46→});
    47→
    48→// POST /api/stripe/create-portal — Customer portal for subscription management
    49→router.post('/create-portal', verifyToken, async (req, res) => {
    50→  const user = req.user;
    51→
    52→  if (!process.env.STRIPE_SECRET_KEY || process.env.STRIPE_SECRET_KEY.includes('placeholder')) {
    53→    return res.status(503).json({ error: 'Payment system not configured yet.' });
    54→  }
    55→
    56→  try {
    57→    // Find Stripe customer by email
    58→    const customers = await stripe.customers.list({ email: user.email, limit: 1 });
    59→    if (customers.data.length === 0) {
    60→      return res.status(404).json({ error: 'No Stripe customer found for this user' });
    61→    }
    62→    const customerId = customers.data[0].id;
    63→
    64→    const session = await stripe.billingPortal.sessions.create({
    65→      customer: customerId,
    66→      return_url: `${process.env.FRONTEND_URL}/settings`,
    67→    });
    68→
    69→    res.json({ url: session.url });
    70→  } catch (err) {
    71→    console.error('[Stripe Portal Error]', err.message);
    72→    res.status(500).json({ error: err.message });
    73→  }
    74→});
    75→
    76→// GET /api/stripe/subscription — Get subscription status
    77→router.get('/subscription', verifyToken, async (req, res) => {
    78→  if (!process.env.STRIPE_SECRET_KEY || process.env.STRIPE_SECRET_KEY.includes('placeholder')) {
    79→    return res.json({ subscription: 'free', plan: 'free' });
    80→  }
    81→
    82→  try {
    83→    const customers = await stripe.customers.list({ email: req.user.email, limit: 1 });
    84→    if (customers.data.length === 0) {
    85→      return res.json({ subscription: 'free', plan: 'free' });
    86→    }
    87→
    88→    const subscriptions = await stripe.subscriptions.list({
    89→      customer: customers.data[0].id,
    90→      status: 'active',
    91→      limit: 1,
    92→    });
    93→
    94→    if (subscriptions.data.length === 0) {
    95→      return res.json({ subscription: 'free', plan: 'free' });
    96→    }
    97→
    98→    const sub = subscriptions.data[0];
    99→    const priceId = sub.items.data[0].price.id;
   100→
   101→    let plan = 'free';
   102→    if (priceId === process.env.STRIPE_GROW_PRICE_ID) plan = 'grow';
   103→    if (priceId === process.env.STRIPE_SCALE_PRICE_ID) plan = 'scale';
   104→    if (priceId === process.env.STRIPE_EVOLUTION_PRICE_ID) plan = 'evolution';
   105→
   106→    res.json({
   107→      subscription: plan,
   108→      plan,
   109→      status: sub.status,
   110→      currentPeriodEnd: sub.current_period_end,
   111→      cancelAtPeriodEnd: sub.cancel_at_period_end,
   112→    });
   113→  } catch (err) {
   114→    console.error('[Stripe Subscription Error]', err.message);
   115→    res.json({ subscription: 'free', plan: 'free' });
   116→  }
   117→});
   118→
   119→// POST /api/stripe/webhook — Handle Stripe webhooks
   120→router.post('/webhook', express.raw({ type: 'application/json' }), async (req, res) => {
   121→  const sig = req.headers['stripe-signature'];
   122→
   123→  if (!process.env.STRIPE_WEBHOOK_SECRET || process.env.STRIPE_WEBHOOK_SECRET.includes('placeholder')) {
   124→    console.warn('[Stripe Webhook] Webhook secret not configured');
   125→    return res.json({ received: true });
   126→  }
   127→
   128→  let event;
   129→  try {
   130→    event = stripe.webhooks.constructEvent(req.body, sig, process.env.STRIPE_WEBHOOK_SECRET);
   131→  } catch (err) {
   132→    console.error('[Stripe Webhook] Signature verification failed:', err.message);
   133→    return res.status(400).send(`Webhook Error: ${err.message}`);
   134→  }
   135→
   136→  // Handle subscription events
   137→  switch (event.type) {
   138→    case 'checkout.session.completed': {
   139→      const session = event.data.object;
   140→      const firebaseUid = session.metadata?.firebaseUid || session.client_reference_id;
   141→      if (firebaseUid) {
   142→        await updateUserSubscription(firebaseUid, session.subscription, 'pro');
   143→      }
   144→      break;
   145→    }
   146→
   147→    case 'customer.subscription.updated': {
   148→      const sub = event.data.object;
   149→      const firebaseUid = sub.metadata?.firebaseUid;
   150→      if (firebaseUid) {
   151→        const priceId = sub.items.data[0]?.price?.id;
   152→        let plan = 'free';
   153→        if (priceId === process.env.STRIPE_GROW_PRICE_ID) plan = 'grow';
   154→        if (priceId === process.env.STRIPE_SCALE_PRICE_ID) plan = 'scale';
   155→        if (priceId === process.env.STRIPE_EVOLUTION_PRICE_ID) plan = 'evolution';
   156→        if (sub.status !== 'active') plan = 'free';
   157→        await updateUserSubscription(firebaseUid, sub.id, plan);
   158→      }
   159→      break;
   160→    }
   161→
   162→    case 'customer.subscription.deleted': {
   163→      const sub = event.data.object;
   164→      const firebaseUid = sub.metadata?.firebaseUid;
   165→      if (firebaseUid) {
   166→        await updateUserSubscription(firebaseUid, null, 'free');
   167→      }
   168→      break;
   169→    }
   170→
   171→    default:
   172→      break;
   173→  }
   174→
   175→  res.json({ received: true });
   176→});
   177→
   178→// Update user subscription in Firestore
   179→async function updateUserSubscription(uid, subscriptionId, plan) {
   180→  try {
   181→    const admin = require('firebase-admin');
   182→    // Only update if firebase is initialized
   183→    if (admin.apps.length > 0) {
   184→      const db = admin.firestore();
   185→      // Never overwrite admin subscription — admin access is manually assigned
   186→      const existing = await db.collection('users').doc(uid).get();
   187→      if (existing.exists && existing.data().subscription === 'admin') {
   188→        console.log(`[Webhook] Skipping update for admin user ${uid}`);
   189→        return;
   190→      }
   191→      await db.collection('users').doc(uid).update({
   192→        subscription: plan,
   193→        stripeSubscriptionId: subscriptionId,
   194→        updatedAt: admin.firestore.FieldValue.serverTimestamp(),
   195→      });
   196→      console.log(`[Webhook] Updated user ${uid} subscription to ${plan}`);
   197→    }
   198→  } catch (err) {
   199→    console.error('[Webhook] Failed to update Firestore:', err.message);
   200→  }
   201→}
   202→
   203→module.exports = router;
   204→

